const item = $input.first();
const binary = item.binary || {};
const keys = Object.keys(binary);
const VALID_TYPES = ['application/pdf','image/jpeg','image/jpg','image/png','image/webp'];
const attKey = keys.find(k => VALID_TYPES.includes((binary[k].mimeType || '').toLowerCase()));
if (!attKey) return [{ json: { hasAttachment: false } }];
const att = binary[attKey];
const mime = att.mimeType.toLowerCase();
return [{ json: {
  hasAttachment: true,
  fileBase64: att.data,
  mimeType: mime,
  fileName: att.fileName || ('factura_' + Date.now() + (mime.includes('pdf') ? '.pdf' : '.jpg')),
  subject: item.json.subject || '',
  from: item.json.from || ''
} }];

const d = $input.first().json;
const isPdf = d.mimeType.includes('pdf');
const contentBlock = isPdf
  ? { type: 'document', source: { type: 'base64', media_type: d.mimeType, data: d.fileBase64 } }
  : { type: 'image',    source: { type: 'base64', media_type: d.mimeType, data: d.fileBase64 } };
const body = JSON.stringify({
  model: 'claude-opus-4-5',
  max_tokens: 10,
  messages: [{
    role: 'user',
    content: [
      contentBlock,
      { type: 'text', text: 'Analiza este documento. ¿Es una FACTURA (tiene número de factura, importe, IVA, datos del emisor)? Responde ÚNICAMENTE con una palabra: factura o no.' }
    ]
  }]
});
return [{ json: { ...d, claudeBody: body } }];

const d = $('Extraer adjunto').first().json;
const isPdf = d.mimeType.includes('pdf');
const contentBlock = isPdf
  ? { type: 'document', source: { type: 'base64', media_type: d.mimeType, data: d.fileBase64 } }
  : { type: 'image',    source: { type: 'base64', media_type: d.mimeType, data: d.fileBase64 } };
const prompt = 'Extrae los datos de esta factura y devuelve SOLO un JSON válido (sin markdown, sin texto extra) con exactamente estos campos:
{
  "tipo": "gasto",
  "fecha": "DD/MM/YYYY",
  "numero_factura": "",
  "proveedor_cliente": "",
  "nif_cif": "",
  "concepto": "",
  "base_imponible": 0,
  "iva_porcentaje": 21,
  "iva_importe": 0,
  "total": 0,
  "categoria": "Otros",
  "estado": "pendiente"
}
Categorías válidas: Telas y materiales, Transporte y envíos, Marketing y publicidad, Equipamiento y maquinaria, Servicios externos, Nóminas, Alquiler, Suministros, Otros.
Fecha siempre en formato DD/MM/YYYY. Si no encuentras un campo déjalo vacío o en 0.';
const body = JSON.stringify({
  model: 'claude-opus-4-5',
  max_tokens: 1024,
  messages: [{ role: 'user', content: [ contentBlock, { type: 'text', text: prompt } ] }]
});
return [{ json: { ...d, claudeBody: body } }];

const resp = $input.first().json;
const adj = $('Extraer adjunto').first().json;
const text = (resp.content[0].text || '').trim();
let datos;
try {
  const match = text.match(/\{[\s\S]*\}/);
  datos = JSON.parse(match ? match[0] : text);
} catch(e) {
  datos = { tipo:'gasto', fecha:'', numero_factura:'', proveedor_cliente:'', nif_cif:'', concepto:'', base_imponible:0, iva_porcentaje:21, iva_importe:0, total:0, categoria:'Otros', estado:'pendiente' };
}
// Calcular trimestre y año desde la fecha extraída
let trimestre = 'T' + Math.ceil(((new Date().getMonth()+1)/3));
let anyo = String(new Date().getFullYear());
if (datos.fecha) {
  const parts = datos.fecha.split('/');
  if (parts.length === 3) {
    const mes = parseInt(parts[1], 10);
    trimestre = mes <= 3 ? 'T1' : mes <= 6 ? 'T2' : mes <= 9 ? 'T3' : 'T4';
    anyo = parts[2] || anyo;
  }
}
const driveBody = JSON.stringify({
  file:      adj.fileBase64,
  nombre:    adj.fileName,
  mimeType:  adj.mimeType,
  trimestre,
  anyo,
  tipo:      'gasto'
});
return [{ json: { datos, adj, trimestre, anyo, driveBody } }];
